// Определяем что пришло: уже извлечённый текст (от браузера) или бинарный файл.
// n8n webhook кладёт JSON-body в $json.body, а form-data поля в корень.
// Поэтому ищем text и в .body, и в корне для надёжности.

const item = $input.first();
const root = item.json || {};
const body = (root.body && typeof root.body === 'object') ? root.body : {};
const binary = item.binary || {};
const binaryKeys = Object.keys(binary);

function pick(field) {
  if (typeof body[field] === 'string' && body[field].length > 0) return body[field];
  if (typeof root[field] === 'string' && root[field].length > 0) return root[field];
  return null;
}

const text = pick('text');
const fileName = pick('fileName') || 'document.txt';
const source = pick('source') || 'browser';

// Браузерный путь: JSON с готовым текстом
if (text && text.trim().length > 0) {
  return [{
    json: {
      has_text: true,
      text: text,
      fileName: fileName,
      source: source
    }
  }];
}

// Файловый путь: есть binary
if (binaryKeys.length > 0) {
  const key = binaryKeys[0];
  const info = binary[key];
  const realFileName = info.fileName || 'unknown';
  const fileSize = info.fileSize || 0;

  if (fileSize > 50 * 1024 * 1024) {
    return [{ json: { has_text: false, has_file: false, error: 'Файл слишком большой (макс. 50 МБ).' } }];
  }

  return [{
    json: {
      has_text: false,
      has_file: true,
      binaryKey: key,
      fileName: realFileName,
      mimeType: info.mimeType || 'unknown'
    },
    binary: binary
  }];
}

// Ничего не пришло — лог что было в root для отладки
const rootKeys = Object.keys(root).slice(0, 10).join(',');
return [{ json: { has_text: false, has_file: false, error: 'Файл не загружен и текст не передан. (Получено: root=[' + rootKeys + '])' } }];

// Извлекаем текст из ответа OCR (только если файл проходил через OCR ветку).
try {
  const data = $input.first().json;

  if (data.error) {
    const msg = typeof data.error === 'string' ? data.error : (data.error.message || JSON.stringify(data.error));
    return [{ json: { has_text: false, error: 'OCR ошибка: ' + msg } }];
  }

  let text = '';
  if (typeof data === 'string') text = data;
  else if (data.text && typeof data.text === 'string') text = data.text;
  else if (data.result && typeof data.result === 'string') text = data.result;
  else if (data.result && data.result.text) text = data.result.text;
  else if (data.content && typeof data.content === 'string') text = data.content;
  else if (data.data && typeof data.data === 'string') text = data.data;
  else if (data.output && typeof data.output === 'string') text = data.output;
  else text = JSON.stringify(data);

  text = text.trim();

  if (!text || text === '{}' || text === '[]' || text === 'null' || text.length < 3) {
    return [{ json: { has_text: false, error: 'OCR не смог распознать текст. Попробуйте другой файл.' } }];
  }

  // fileName тянем из «Определить вход»
  const fileName = $('Определить вход').first().json.fileName || 'unknown';
  return [{ json: { has_text: true, text: text, fileName: fileName, source: 'ocr' } }];
} catch (e) {
  return [{ json: { has_text: false, error: 'Ошибка обработки OCR: ' + e.message } }];
}

// Нарезаем текст на куски по ~500 слов с перекрытием 50 слов.
// На входе $json.text (от браузера) или после OCR — тоже text.
const text = $json.text;
const fileName = $json.fileName;
const source = $json.source || 'unknown';

const CHUNK_SIZE = 500;
const OVERLAP = 50;

const words = String(text || '').split(/\s+/).filter(w => w.length > 0);

if (words.length === 0) {
  return [{ json: { error: 'Текст пустой после обработки.' } }];
}

const chunks = [];
let start = 0;

while (start < words.length) {
  const end = Math.min(start + CHUNK_SIZE, words.length);
  const chunkText = words.slice(start, end).join(' ');

  chunks.push({
    json: {
      fileName: fileName,
      chunk_index: chunks.length,
      chunk_text: chunkText,
      total_chunks: 0,
      source: source
    }
  });

  if (end >= words.length) break;
  start += CHUNK_SIZE - OVERLAP;
}

for (const chunk of chunks) {
  chunk.json.total_chunks = chunks.length;
}

return chunks;

// Эмбеддинг через embedding-server. Используем fallback URL — host.docker.internal
// для Docker n8n (дома), 127.0.0.1 для нативного n8n (офис). На ENOTFOUND/
// ECONNREFUSED пробуем следующий URL.

const URLS = [
  'http://host.docker.internal:8001/embed',
  'http://127.0.0.1:8001/embed'
];

const chunkText = $json.chunk_text;
const payload = JSON.stringify({ input: chunkText, type: 'passage' });

const NET_ERR = ['ECONNREFUSED','ENOTFOUND','EHOSTUNREACH','EAI_AGAIN','ETIMEDOUT','ECONNABORTED','ECONNRESET'];

let lastErr = '';
for (const url of URLS) {
  try {
    const r = await this.helpers.httpRequest({
      method: 'POST',
      url: url,
      body: payload,
      headers: { 'Content-Type': 'application/json' },
      json: false,
      returnFullResponse: true,
      ignoreHttpStatusErrors: true,
      timeout: 60000
    });
    const status = r.statusCode || r.status || 0;
    if (status >= 200 && status < 300) {
      // Парсим JSON тело
      let data = r.body;
      if (typeof data === 'string') {
        try { data = JSON.parse(data); } catch (_) {}
      } else if (data && data.type === 'Buffer' && Array.isArray(data.data)) {
        try { data = JSON.parse(Buffer.from(data.data).toString('utf8')); } catch (_) {}
      } else if (Buffer.isBuffer && Buffer.isBuffer(data)) {
        try { data = JSON.parse(data.toString('utf8')); } catch (_) {}
      }
      return [{ json: data }];
    }
    // HTTP 4xx/5xx — это ошибка сервиса, не сетевая. Сразу прокидываем.
    let bodyText = '';
    try {
      const b = r.body;
      if (Buffer.isBuffer(b)) bodyText = b.toString('utf8');
      else if (typeof b === 'string') bodyText = b;
      else if (b && b.type === 'Buffer' && Array.isArray(b.data)) bodyText = Buffer.from(b.data).toString('utf8');
      else bodyText = JSON.stringify(b);
    } catch (_) {}
    return [{ json: { error: 'Embedding HTTP ' + status + ': ' + bodyText.slice(0, 300) } }];
  } catch (e) {
    const code = (e.cause && e.cause.code) || e.code || '';
    if (NET_ERR.includes(code) || /timeout|econnrefused|enotfound|connect|getaddrinfo/i.test(String(e.message || ''))) {
      lastErr = (e.message || String(e)) + ' (' + url + ')';
      continue;
    }
    return [{ json: { error: 'Embedding исключение: ' + (e.message || String(e)) } }];
  }
}

return [{ json: { error: 'Embedding-сервер недоступен. Проверь что embedding-server запущен на порту 8001. Последняя ошибка: ' + lastErr } }];

// Извлекаем вектор из ответа эмбеддинга и готовим SQL.
try {
  const data = $input.first().json;
  const prevData = $('Нарезка на куски').first().json;
  const fileName = prevData.fileName;
  const chunkIndex = prevData.chunk_index;
  const chunkText = prevData.chunk_text;
  const totalChunks = prevData.total_chunks;

  if (data.error) {
    return [{ json: { success: false, error: 'Ошибка эмбеддинга: ' + JSON.stringify(data.error) } }];
  }

  let vector = null;
  if (data.data && Array.isArray(data.data) && data.data[0] && data.data[0].embedding) {
    vector = data.data[0].embedding;
  } else if (data.embedding && Array.isArray(data.embedding)) {
    vector = data.embedding;
  } else if (Array.isArray(data) && data.length > 0 && typeof data[0] === 'number') {
    vector = data;
  }

  if (!vector || vector.length === 0) {
    return [{ json: { success: false, error: 'Эмбеддинг вернул пустой вектор.' } }];
  }

  const safeText = chunkText.replaceAll("'", "''");
  const safeFileName = fileName.replaceAll("'", "''");
  const vectorStr = '[' + vector.join(',') + ']';

  // ON CONFLICT UPDATE — идемпотентность повторной загрузки: тот же файл
  // обновляет чанки, а не дублирует. Требует UNIQUE constraint на
  // (filename, chunk_index) в схеме (см. PostgreSQL-Guide.md).
  const sql = `INSERT INTO documents (filename, chunk_index, chunk_text, embedding) VALUES ('${safeFileName}', ${chunkIndex}, '${safeText}', '${vectorStr}') ON CONFLICT (filename, chunk_index) DO UPDATE SET chunk_text = EXCLUDED.chunk_text, embedding = EXCLUDED.embedding, created_at = NOW()`;

  return [{ json: {
    success: true,
    sql: sql,
    fileName: fileName,
    chunk_index: chunkIndex,
    total_chunks: totalChunks,
    vector_size: vector.length
  }}];
} catch (e) {
  return [{ json: { success: false, error: 'Ошибка обработки эмбеддинга: ' + e.message } }];
}

// Агрегируем результаты записи всех кусков.
function errToString(e) {
  if (!e) return '';
  if (typeof e === 'string') return e;
  if (typeof e === 'object') {
    if (e.message) return String(e.message);
    if (e.detail) return String(e.detail);
    try { return JSON.stringify(e); } catch (_) { return String(e); }
  }
  return String(e);
}

const items = $input.all();
let success = 0;
let failed = 0;
let errors = [];
let fileName = '';
let totalChunks = 0;
let source = '';

for (const item of items) {
  const prev = item.json || {};
  if (!fileName && prev.fileName) fileName = prev.fileName;
  if (!totalChunks && prev.total_chunks) totalChunks = prev.total_chunks;
  if (!source && prev.source) source = prev.source;
  if (prev.error) {
    failed++;
    errors.push(errToString(prev.error));
  } else {
    success++;
  }
}

if (success === 0 && failed === 0) {
  success = items.length;
}

if (!fileName) {
  try { fileName = $('Нарезка на куски').first().json.fileName; } catch (_) {}
}
if (!source) {
  try { source = $('Нарезка на куски').first().json.source; } catch (_) {}
}

const sourceLabel = source === 'browser' ? ' (без OCR — текст извлечён в браузере)'
                  : source === 'ocr'     ? ' (через OCR)' : '';

let message = '';
if (failed === 0) {
  message = 'Документ "' + fileName + '" успешно загружен' + sourceLabel + '!\n' +
    'Сохранено кусков: ' + success + '\n' +
    'Документ теперь доступен для поиска по смыслу через агента по документам.';
} else {
  // Уникальные ошибки
  const uniqErrors = Array.from(new Set(errors)).slice(0, 3);
  message = 'Документ "' + fileName + '" загружен частично' + sourceLabel + '.\n' +
    'Успешно: ' + success + ', ошибок: ' + failed + '\n' +
    'Ошибки: ' + uniqErrors.join(' | ');
}

return [{ json: { response: message } }];
